const data = $input.first().json;
const execution = data.execution || {};
const error = execution.error || {};
const workflow = data.workflow || {};

const failedNode = error.node ? error.node.name : 'Unknown Node';
const errorMessage = error.message || 'No error message';
const errorStack = error.stack || 'No traceback logs available';
const executionUrl = execution.url || '#';
const workflowName = workflow.name || 'Unknown Workflow';

const html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <style>
    body {
      font-family: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
      background-color: #0f0f15;
      color: #e4e4e9;
      margin: 0;
      padding: 40px 20px;
    }
    .container {
      max-width: 650px;
      margin: 0 auto;
      background-color: #161622;
      border-radius: 12px;
      border: 1px solid #2e2e3f;
      overflow: hidden;
      box-shadow: 0 10px 30px rgba(0, 0, 0, 0.4);
    }
    .header {
      background: linear-gradient(135deg, #ff416c, #ff4b2b);
      padding: 30px 40px;
      text-align: center;
    }
    .header h1 {
      margin: 0;
      font-size: 24px;
      font-weight: 700;
      color: #ffffff;
      letter-spacing: -0.5px;
    }
    .content {
      padding: 40px;
    }
    .summary-table {
      width: 100%;
      border-collapse: collapse;
      margin-bottom: 30px;
    }
    .summary-table td {
      padding: 12px 0;
      border-bottom: 1px solid #2e2e3f;
      font-size: 15px;
    }
    .summary-table td.label {
      font-weight: 600;
      color: #8f8fa3;
      width: 35%;
    }
    .summary-table td.value {
      color: #e4e4e9;
      font-weight: 500;
    }
    .summary-table tr:last-child td {
      border-bottom: none;
    }
    .btn-wrapper {
      text-align: center;
      margin: 30px 0 10px 0;
    }
    .btn {
      background-color: #3b82f6;
      color: #ffffff !important;
      padding: 12px 28px;
      text-decoration: none;
      border-radius: 6px;
      font-weight: 600;
      font-size: 15px;
      display: inline-block;
      box-shadow: 0 4px 14px rgba(59, 130, 246, 0.4);
      transition: background-color 0.2s;
    }
    .btn:hover {
      background-color: #2563eb;
      color: #ffffff !important;
    }
    .trace-header {
      font-size: 16px;
      font-weight: 600;
      color: #ff8e8e;
      margin-top: 30px;
      margin-bottom: 10px;
    }
    .traceback {
      background-color: #0d0d12;
      border: 1px solid #2e2e3f;
      border-radius: 6px;
      padding: 20px;
      font-family: "SFMono-Regular", Consolas, "Liberation Mono", Menlo, monospace;
      font-size: 13px;
      color: #ff6565;
      line-height: 1.6;
      overflow-x: auto;
      white-space: pre-wrap;
      word-break: break-all;
      max-height: 300px;
      overflow-y: auto;
    }
    .footer {
      text-align: center;
      padding: 20px 40px;
      background-color: #0f0f15;
      border-top: 1px solid #2e2e3f;
      font-size: 12px;
      color: #64748b;
    }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>🚨 Multi-Agent Workflow Failure</h1>
    </div>
    <div class="content">
      <table class="summary-table">
        <tr>
          <td class="label">Workflow Name</td>
          <td class="value">${workflowName}</td>
        </tr>
        <tr>
          <td class="label">Workflow ID</td>
          <td class="value"><code>${workflow.id || 'N/A'}</code></td>
        </tr>
        <tr>
          <td class="label">Execution ID</td>
          <td class="value"><code>${execution.id || 'N/A'}</code></td>
        </tr>
        <tr>
          <td class="label">Failed Node</td>
          <td class="value"><strong>${failedNode}</strong></td>
        </tr>
        <tr>
          <td class="label">Error Message</td>
          <td class="value" style="color: #ff6565;">${errorMessage}</td>
        </tr>
      </table>

      <div class="btn-wrapper">
        <a href="${executionUrl}" class="btn" target="_blank">Inspect Execution in n8n</a>
      </div>

      <div class="trace-header">Traceback / Stack Logs:</div>
      <pre class="traceback">${errorStack}</pre>
    </div>
    <div class="footer">
      Powered by <strong>AI Engineer OS</strong> · Automation Engine &copy; 2026
    </div>
  </div>
</body>
</html>
`;

return [{ json: { html_body: html, developer_email: "developer@yourdomain.com", workflow_id: workflow.id } }];
